import pandas as pd

def most_corr(prices_df):
    pct_change = prices_df.pct_change().dropna()
    corr_matrix = pct_change.corr()
    mask = corr_matrix.abs().stack().sort_values(ascending=False).index
    ticker1, ticker2 = mask[0]
    return (ticker1, ticker2)

def main():
    data = pd.read_csv("data.csv", index_col=0)
    ticker1, ticker2 = most_corr(data)
    result = pd.DataFrame({
        "Ticker 1": [ticker1],
        "Ticker 2": [ticker2]
    })
    result.to_csv("most_corr_output.csv", index=False)

if __name__ == "__main__":
    main()
